import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function q(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rpn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  q("REX-PN","Cardiovascular",3,"A client with Raynaud phenomenon should be taught to:",["Apply cold compresses to hands","Avoid cold exposure and emotional stress, and stop smoking","Exercise vigorously in cold weather","Use tight-fitting gloves for warmth"],1,"Raynaud phenomenon causes episodic vasospasm in digits triggered by cold and stress. Clients should avoid cold exposure, wear layered warm clothing, manage stress, and avoid smoking (nicotine causes vasoconstriction)."),
  q("REX-PN","Cardiovascular",3,"A client with a central venous catheter develops signs of air embolism. The nurse should position the client in:",["Left lateral Trendelenburg position to trap air in the right atrium","Right lateral position with head elevated","Prone position","Sitting upright"],0,"Left lateral Trendelenburg position traps air in the right atrium, preventing it from entering the pulmonary artery. Clamp the catheter to prevent further air entry. Administer oxygen and notify the physician."),
  q("RPN-CAT","Cardiovascular",3,"A client post-cardiac surgery develops pericardial tamponade. Classic Beck triad includes:",["Hypertension, tachycardia, fever","Hypotension, distended neck veins, muffled heart sounds","Bradycardia, hypertension, irregular respirations","Tachycardia, crackles, peripheral edema"],1,"Beck triad (hypotension, muffled heart sounds, JVD) is the classic presentation of cardiac tamponade from pericardial fluid compressing the heart. Pulsus paradoxus may also be present. Emergency pericardiocentesis is required."),
  q("REX-PN","Cardiovascular",2,"The nurse performs orthostatic blood pressure measurements. A positive finding of orthostatic hypotension is defined as:",["A 5 mmHg drop in systolic pressure","A drop of 20 mmHg systolic or 10 mmHg diastolic upon standing","Any change in blood pressure","A 30 mmHg increase in systolic pressure"],1,"Orthostatic hypotension is defined as a sustained reduction of SBP >= 20 mmHg or DBP >= 10 mmHg within 3 minutes of standing, or symptoms of cerebral hypoperfusion. Common in elderly, dehydrated, or medication-affected patients."),
  q("REX-PN","Respiratory",3,"A client with a thoracotomy has subcutaneous emphysema extending from the chest tube site. The nurse should:",["Remove the chest tube immediately","Mark the borders, notify the provider, and monitor progression","Apply ice to the affected area","Increase suction pressure"],1,"Subcutaneous emphysema (crepitus) indicates air leaking into subcutaneous tissue. The nurse marks borders with a skin marker, monitors for progression (particularly toward the neck which could compromise the airway), and notifies the provider."),
  q("REX-PN","Respiratory",2,"The nurse teaches a client to use a metered-dose inhaler properly. The correct technique includes:",["Inhaling quickly and deeply after pressing the canister","Exhaling fully first, then inhaling slowly and deeply while activating the MDI","Holding the breath for 2 seconds then exhaling forcefully","Placing the inhaler inside the mouth and biting down on it"],1,"Proper MDI technique includes exhaling fully, placing the mouthpiece in the mouth, pressing the canister while beginning a slow deep inhalation, and holding the breath for 10 seconds to allow medication deposition."),
  q("RPN-CAT","Respiratory",3,"The most effective nursing intervention to prevent ventilator-associated pneumonia includes:",["Changing the ventilator circuit daily","Elevating the head of bed 30-45 degrees and performing oral care with chlorhexidine","Using prophylactic antibiotics for all ventilated patients","Keeping the cuff deflated during feedings"],1,"The VAP prevention bundle includes HOB elevation 30-45 degrees, oral care with chlorhexidine every 4-6 hours, daily sedation vacation, readiness-to-extubate assessment, and DVT/stress ulcer prophylaxis."),
  q("REX-PN","Neurological",3,"A client with late-stage Alzheimer disease is dependent for all ADLs. The priority nursing focus is:",["Cognitive rehabilitation programs","Comfort, safety, and dignity maintenance","Memory-enhancing medications","Group socialization activities"],1,"Late-stage Alzheimer care focuses on comfort measures, maintaining dignity, adequate nutrition (may need assistance or alternative feeding), skin integrity, pain management, and family support. The client is fully dependent for all care."),
  q("REX-PN","Neurological",2,"A client with carpal tunnel syndrome has numbness in the thumb, index, and middle finger. This involves compression of the:",["Ulnar nerve","Median nerve at the wrist","Radial nerve","Brachial plexus"],1,"The median nerve passes through the carpal tunnel. Compression causes pain, numbness, and tingling in the thumb, index, middle finger, and radial half of the ring finger. Treatment begins with night splinting and may progress to surgery."),
  q("RPN-CAT","Neurological",3,"A client with a VP shunt presents with headache, nausea, and altered consciousness. The nurse suspects:",["Migraine headache","VP shunt malfunction causing increased intracranial pressure","Medication side effect","Gastroenteritis"],1,"VP shunt malfunction prevents CSF drainage, causing ICP elevation. Signs include headache, nausea/vomiting, altered consciousness, and in infants, bulging fontanelle. Urgent neurosurgical evaluation is needed for possible shunt revision."),
  q("REX-PN","Endocrine",3,"A client with type 1 diabetes whose insulin pump malfunctions should be instructed to:",["Wait for the pump to restart","Immediately switch to subcutaneous injections per backup plan","Drink extra fluids only","Skip insulin until the next meal"],1,"Pump malfunction can rapidly lead to DKA since only rapid-acting insulin is used (no long-acting depot). Immediate transition to subcutaneous injections per the prescribed backup regimen is essential to maintain glycemic control."),
  q("REX-PN","Endocrine",2,"Which symptoms are characteristic of hypothyroidism?",["Heat intolerance and weight loss","Cold intolerance, weight gain, fatigue, and constipation","Exophthalmos and tremor","Diarrhea and anxiety"],1,"Hypothyroidism causes slowed metabolism resulting in cold intolerance, weight gain, fatigue, constipation, dry skin, hair loss, bradycardia, and mental sluggishness. Treatment is thyroid hormone replacement with levothyroxine."),
  q("REX-PN","Gastrointestinal",3,"Hepatitis C is confirmed through which diagnostic test sequence?",["Hepatitis C surface antigen test","HCV antibody screening followed by HCV RNA viral load confirmation","ALT level measurement alone","Liver biopsy as first test"],1,"HCV diagnosis begins with antibody screening. Positive antibody results are confirmed with HCV RNA PCR testing to distinguish active infection from resolved past infection. Genotype testing then guides antiviral treatment selection."),
  q("RPN-CAT","Gastrointestinal",3,"During an acute diverticulitis episode, dietary management includes:",["High-fiber diet immediately","Clear liquid diet initially, advancing to low-fiber as symptoms improve","Regular diet with fiber supplements","Nothing by mouth for 2 weeks"],1,"Acute diverticulitis requires bowel rest with clear liquids to reduce inflammation. As symptoms improve, advance to low-fiber, then gradually increase fiber to 25-30g/day during recovery to prevent recurrence."),
  q("REX-PN","Gastrointestinal",2,"A positive fecal occult blood test result requires the nurse to:",["Diagnose colon cancer","Explain further evaluation with colonoscopy is needed","Repeat the test in 12 months","Prescribe iron supplements"],1,"A positive FOBT/FIT indicates blood in the stool but is not diagnostic. Follow-up colonoscopy identifies the source (polyps, cancer, hemorrhoids, or other GI conditions) and enables biopsy or treatment if needed."),
  q("REX-PN","Pharmacology",3,"Metoclopramide can cause which significant adverse effect the nurse should monitor?",["Hepatotoxicity","Extrapyramidal symptoms including tardive dyskinesia","Nephrotoxicity","Hyperglycemia"],1,"Metoclopramide blocks dopamine receptors, potentially causing EPS including acute dystonia, akathisia, and tardive dyskinesia with prolonged use. Treatment should be limited to 12 weeks maximum. Contraindicated in Parkinson disease patients."),
  q("REX-PN","Pharmacology",2,"A client receiving IV antibiotics develops a rash and itching. The nurse's first action is to:",["Continue the infusion and give diphenhydramine","Stop the infusion immediately and maintain IV access","Increase the rate to finish the dose","Apply hydrocortisone cream and continue"],1,"An allergic reaction requires immediate discontinuation of the offending medication. Maintaining IV access is important for potential emergency interventions. The provider determines alternative therapy."),
  q("RPN-CAT","Pharmacology",3,"A client on statin therapy should report which symptom immediately?",["Mild headache","Unexplained muscle pain with dark-colored urine","Decreased appetite","Mild nausea"],1,"Unexplained myalgia with dark urine may indicate rhabdomyolysis, a rare but serious complication. Dark urine results from myoglobin released from damaged muscle tissue. CK levels and renal function require immediate evaluation."),
  q("REX-PN","Pharmacology",2,"When administering a sublingual medication, the nurse instructs the client to:",["Chew the tablet thoroughly","Place it under the tongue without swallowing until fully dissolved","Swallow it with a full glass of water","Crush it and mix with applesauce"],1,"Sublingual medications dissolve under the tongue for direct absorption into the bloodstream through the sublingual mucosa, bypassing first-pass hepatic metabolism. The client should avoid eating, drinking, or swallowing until fully dissolved."),
  q("REX-PN","Mental Health",3,"A client with antisocial personality disorder attempts manipulation to obtain special treatment. The nurse should:",["Grant the request to develop therapeutic rapport","Maintain clear, consistent boundaries without negotiation","Avoid all contact with the client","Allow the behavior and document only"],1,"Clients with antisocial personality disorder require firm, consistent limit-setting. Manipulation attempts should not be reinforced. Consequences for boundary violations should be clearly communicated and enforced consistently by all staff."),
  q("REX-PN","Mental Health",2,"The least restrictive intervention principle dictates that the nurse should first attempt:",["Seclusion for safety","Physical restraints","Chemical sedation","Verbal de-escalation and environmental modifications"],3,"The least restrictive approach is always tried first: verbal de-escalation, reducing environmental stimuli, offering choices, and therapeutic communication before progressing to more restrictive measures like chemical or physical restraints."),
  q("RPN-CAT","Mental Health",3,"A client abruptly stops their SSRI antidepressant. The nurse should educate about:",["No consequences of sudden discontinuation","SSRI discontinuation syndrome with dizziness, electric shock sensations, and irritability","Immediate improvement in mood","Need for a higher dose upon restarting"],1,"Abrupt SSRI discontinuation causes withdrawal-like symptoms including dizziness, paresthesias (brain zaps), nausea, headache, and irritability. SSRIs should always be tapered gradually under provider supervision."),
  q("REX-PN","Pediatrics",3,"A child prescribed a scoliosis brace should wear it:",["Only at night","During school hours only","23 hours daily, removing only for bathing and exercises","2 hours per day"],2,"Scoliosis braces require 23 hours/day wear for maximum effectiveness. Compliance directly affects treatment outcome. The brace prevents curve progression but does not correct existing curvature."),
  q("REX-PN","Pediatrics",2,"A child with chickenpox should NOT receive which fever medication?",["Acetaminophen","Ibuprofen (controversial, generally allowed)","Aspirin (contraindicated due to Reye syndrome risk)","None of the above"],2,"Aspirin is contraindicated in children with viral infections (varicella, influenza) due to the risk of Reye syndrome, a potentially fatal condition affecting the liver and brain. Acetaminophen is the preferred antipyretic."),
  q("RPN-CAT","Pediatrics",3,"A child with hemophilia A sustains a head injury from a fall. The nurse should:",["Apply ice and observe for 24 hours at home","Administer factor VIII replacement immediately and evaluate for intracranial bleeding","Give aspirin for any headache","Wait for symptoms to develop before treating"],1,"Head trauma in hemophilia requires immediate factor replacement regardless of severity, as even minor injuries can cause life-threatening intracranial hemorrhage. CT scan is indicated to rule out bleeding."),
  q("REX-PN","Pediatrics",2,"The nurse teaches safe infant sleep practices. The correct instruction is:",["Place the infant on their stomach to sleep","Place the infant supine on a firm, flat surface without soft bedding","Use bumper pads and blankets for comfort","Co-sleeping with the parent is safest"],1,"Safe sleep ABCs: Alone (own sleep surface), Back (supine position), Crib (firm, flat surface). Remove all soft bedding, pillows, toys, and bumper pads. Room-sharing without bed-sharing for the first 6-12 months reduces SIDS risk."),
  q("REX-PN","Fundamentals",2,"When performing passive range of motion exercises, the nurse should:",["Push joints beyond resistance for maximum benefit","Support the limb above and below the joint being exercised","Move as quickly as possible to maintain client tolerance","Exercise only painful joints"],1,"ROM exercises require supporting the extremity above and below the joint, moving smoothly and gently, never forcing past resistance or pain. Each joint is moved through its full available range if tolerated."),
  q("REX-PN","Fundamentals",3,"A client on anticoagulant therapy who falls and hits their head requires:",["Ice application and routine monitoring only","Immediate neurological assessment and provider notification","Continued anticoagulant administration without changes","Documentation only with no additional assessment"],1,"Anticoagulated clients are at high risk for intracranial hemorrhage after head trauma, which may develop slowly. Immediate neurological assessment, provider notification, and often CT scanning are required even for seemingly minor head injuries."),
  q("RPN-CAT","Fundamentals",2,"A living will document specifies:",["Who will manage the client's finances","The client's treatment wishes if they become incapacitated","Property distribution after death","Preferred healthcare facility"],1,"A living will documents the client's preferences for medical treatment (resuscitation, ventilation, tube feeding, etc.) if they become unable to communicate their wishes. It is a legally binding advance directive separate from power of attorney."),
  q("REX-PN","Musculoskeletal",3,"The earliest and most reliable sign of compartment syndrome is:",["Pulselessness","Paralysis","Pain disproportionate to the injury, especially with passive stretch","Pallor and paresthesia"],2,"Pain out of proportion to the injury, particularly with passive stretch of the affected muscles, is the earliest and most reliable indicator. Pulselessness is a very late sign. Fasciotomy within 6 hours prevents irreversible tissue damage."),
  q("REX-PN","Musculoskeletal",2,"After a below-knee amputation, the residual limb should be positioned:",["Flexed at the knee with pillow support at all times","Extended to prevent knee flexion contracture","Elevated on multiple pillows indefinitely","In any comfortable position"],1,"Extension prevents hip and knee flexion contractures that would interfere with prosthetic fitting and ambulation. Prone positioning for 30 minutes several times daily also helps prevent contractures."),
  q("REX-PN","Renal",3,"A client with ESRD asks about the biggest long-term risk of kidney transplantation. The nurse explains it is:",["Surgical complications from the initial procedure","Lifelong immunosuppressive therapy with increased infection and malignancy risk","Short-term need for dialysis","Immediate organ rejection only"],1,"Post-transplant immunosuppression is lifelong, significantly increasing susceptibility to infections and certain cancers. Regular monitoring of drug levels, renal function, and cancer screening is essential."),
  q("REX-PN","Maternal/Newborn",3,"A pregnant client at 22 weeks with painless bright red vaginal bleeding most likely has:",["Preterm labor contractions","Placenta previa","Placental abruption","Cervical incompetence"],1,"Painless bright red vaginal bleeding in the second or third trimester is the hallmark of placenta previa. Digital vaginal examination is absolutely contraindicated. Diagnosis is confirmed by ultrasound."),
  q("RPN-CAT","Maternal/Newborn",3,"A pregnant client with worsening preeclampsia should be monitored for:",["Only fetal movement patterns","Headache, visual disturbances, epigastric pain, and worsening proteinuria","Appetite changes and weight loss","Skin color changes"],1,"Signs of severe preeclampsia include persistent headache, visual disturbances (scotomata, blurred vision), epigastric/RUQ pain (hepatic capsule distension), oliguria, and laboratory changes (HELLP syndrome). These indicate the need for delivery."),
  q("REX-PN","Infection Control",2,"N95 respirators are required when caring for clients with:",["MRSA wound infections","Standard contact precaution conditions","Active pulmonary tuberculosis","Clostridium difficile infections"],2,"N95 respirators filter >= 95% of airborne particles and are required for airborne precautions (TB, measles, varicella, disseminated herpes zoster). The nurse must be fit-tested annually for proper seal verification."),
  q("REX-PN","Hematological",3,"A client with polycythemia vera and a hematocrit of 60% should be treated with:",["Blood transfusion to dilute the blood","Therapeutic phlebotomy to reduce red cell mass to hematocrit < 45%","Iron supplementation","Platelet transfusion"],1,"Polycythemia vera causes excessive RBC production. Therapeutic phlebotomy removes 350-500 mL blood to reduce hematocrit to < 45%, decreasing viscosity and thrombotic risk. Hydroxyurea may be added for cytoreduction."),
  q("REX-PN","Integumentary",2,"When assessing cyanosis in a dark-skinned client, the nurse should examine:",["The chest wall and abdomen","Oral mucous membranes, nail beds, and conjunctivae","The forehead and cheeks","The upper arms"],1,"In dark-skinned clients, cyanosis is best assessed in areas with less melanin: oral mucosa (becomes gray/blue), nail beds, palms, soles, and conjunctivae. These sites also better reveal pallor and jaundice."),
  q("REX-PN","Immunological",3,"After treating anaphylaxis with epinephrine, the client should be observed for at least:",["30 minutes then discharged","4-6 hours for potential biphasic reaction","15 minutes only","24 hours minimum in all cases"],1,"Biphasic anaphylaxis (symptom recurrence hours after initial resolution) occurs in up to 20% of cases. Observation for at least 4-6 hours is recommended. Severe reactions may warrant longer observation periods."),
  q("REX-PN","Emergency",3,"A client presents after self-administering an epinephrine auto-injector for an allergic reaction. The nurse should:",["Document the self-injection and discharge the client","Provide additional monitoring and treatment as needed for potential biphasic reaction","Remove the epinephrine auto-injector site and apply ice","Inform the client the reaction has fully resolved"],1,"Clients who self-administer epinephrine still require emergency department evaluation. Additional treatments, monitoring for biphasic anaphylaxis, and observation are necessary. The auto-injector provides only a single dose that may be insufficient."),
  q("REX-PN","Oncology",3,"Superior vena cava syndrome in a cancer client presents with:",["Lower extremity swelling only","Facial, neck, and upper extremity edema with dyspnea and JVD","Abdominal distension and ascites","Isolated back pain"],1,"SVC syndrome results from tumor compression of the superior vena cava, obstructing venous return from the upper body. Classic presentation includes facial/neck/arm edema, JVD, dyspnea, and upper body cyanosis. This is an oncologic emergency."),
  q("RPN-CAT","Oncology",3,"A client receiving chemotherapy develops grade 3 oral mucositis. Nursing management includes:",["Vigorous toothbrushing with a firm brush","Gentle oral care, soft toothbrush, bland rinses, and pain management","Spicy food to stimulate mucosal healing","Restrictive fluid intake"],1,"Chemotherapy-induced mucositis requires gentle oral care every 4 hours and after meals with a soft toothbrush, alcohol-free rinses (normal saline or baking soda), bland/soft/cool foods, and adequate pain management including topical and systemic analgesia."),
  q("REX-PN","Perioperative",3,"Malignant hyperthermia during anesthesia is treated with which specific antidote?",["IV acetaminophen","IV dantrolene sodium","Cooling blankets only","Additional anesthetic agents"],1,"Dantrolene sodium is the specific antidote for malignant hyperthermia, reducing intracellular calcium release from the sarcoplasmic reticulum. Additional interventions include stopping triggering agents, active cooling, hyperventilation, and electrolyte management."),
  q("REX-PN","Safety",3,"When a nurse receives a telephone order, the nurse should:",["Carry it out without verification","Read back the complete order for physician confirmation and document immediately","Write it down and verify at the next visit","Ask another nurse to take the order"],1,"Telephone orders require read-back verification for accuracy. The nurse documents the order with date, time, the ordering physician's name, and the nurse's signature. Most facilities require cosignature within 24 hours."),
  q("REX-PN","Geriatrics",3,"An elderly client falls and presents with a shortened, externally rotated right leg. This suggests:",["Knee ligament tear","Hip fracture","Ankle injury","Lumbar disc problem"],1,"Shortened, externally rotated leg is the classic presentation of a hip fracture. The iliopsoas muscle pulls on the lesser trochanter, causing external rotation and shortening. Immediate immobilization, pain management, and surgical evaluation are required."),
  q("REX-PN","Ethics/Legal",2,"HIPAA legislation primarily protects:",["Nurses from workplace injuries","Client protected health information and privacy","Hospital financial records","Physician credentials"],1,"HIPAA safeguards the confidentiality, integrity, and security of protected health information (PHI). Violations include unauthorized access, sharing without consent, and inadequate data security. Penalties include fines and criminal prosecution."),
  q("REX-PN","Delegation",2,"When unsure about a delegated task, the RPN should:",["Attempt the task anyway","Clarify expectations and verify the task is within scope of practice","Delegate it to someone else","Complete it and document any issues afterward"],1,"If uncertain about a delegated task, the RPN should seek clarification and confirm the task falls within their scope of practice. Performing tasks outside one's competency or scope creates patient safety risks and professional liability."),
  q("REX-PN","Health Promotion",2,"The American Heart Association recommends daily sodium intake be limited to no more than:",["3,500 mg","2,300 mg (ideally 1,500 mg for most adults)","5,000 mg","500 mg"],1,"The AHA recommends limiting sodium to no more than 2,300 mg/day, with an ideal limit of 1,500 mg/day. Excess sodium contributes to hypertension, heart disease, stroke, and kidney disease. Reading food labels helps manage intake."),
  q("REX-PN","Nutrition",2,"A client with celiac disease can safely eat:",["Wheat pasta","Barley soup","Quinoa and rice dishes","Rye bread"],2,"Quinoa and rice are naturally gluten-free and safe for celiac disease. Other safe grains include corn, millet, buckwheat, and amaranth. Wheat, barley, rye, spelt, and related grains contain gluten and must be completely avoided."),
  q("REX-PN","Wound Care",2,"The standard wound irrigation solution is:",["Hydrogen peroxide","Povidone-iodine solution","Normal saline (0.9% NaCl)","Sterile water with bleach"],2,"Normal saline is the standard irrigating solution as it is isotonic and non-cytotoxic to healing tissues. Hydrogen peroxide and povidone-iodine damage fibroblasts and delay wound healing, so they are no longer recommended for wound irrigation."),
  q("RPN-CAT","Cardiovascular",3,"A client with atrial fibrillation has a CHA2DS2-VASc score of 4. The nurse anticipates:",["Aspirin therapy only","Oral anticoagulation with a DOAC or warfarin","No anticoagulation","Rate control medication only"],1,"A CHA2DS2-VASc score >= 2 in men or >= 3 in women indicates high stroke risk requiring oral anticoagulation. DOACs (apixaban, rivaroxaban, dabigatran) are preferred over warfarin for non-valvular AF due to better safety and convenience."),
  q("REX-PN","Respiratory",3,"A client recently extubated develops stridor and hoarseness. The nurse suspects:",["Expected post-extubation changes","Laryngeal edema from intubation trauma","Aspiration pneumonia","Vocal cord polyps"],1,"Post-extubation stridor suggests laryngeal edema from endotracheal tube trauma. Treatment includes nebulized racemic epinephrine, IV corticosteroids (dexamethasone), and close airway monitoring. Severe cases may require reintubation."),
  q("REX-PN","Neurological",3,"A client with hepatic encephalopathy demonstrates asterixis. This finding is described as:",["Rhythmic tremor at rest","Flapping tremor of outstretched hands when wrists are dorsiflexed","Muscle rigidity on passive movement","Pill-rolling movements of the fingers"],1,"Asterixis (liver flap) is an involuntary flapping movement when the hands are outstretched with wrists extended. It results from impaired maintenance of posture due to ammonia toxicity and is a hallmark of hepatic encephalopathy."),
  q("REX-PN","Endocrine",3,"Primary hyperaldosteronism (Conn syndrome) typically presents with:",["Hyperkalemia and hypotension","Hypokalemia, hypertension, and metabolic alkalosis","Hypoglycemia and weight loss","Hypercalcemia and polyuria"],1,"Excess aldosterone causes sodium retention (hypertension), potassium excretion (hypokalemia), and hydrogen ion excretion (metabolic alkalosis). Spironolactone (aldosterone antagonist) and possible adrenalectomy are treatments."),
  q("REX-PN","Gastrointestinal",2,"A proton pump inhibitor should be taken:",["After the evening meal","30 minutes before the first meal of the day for optimal effect","With a large high-fat meal","Only when symptoms occur"],1,"PPIs are most effective when taken 30 minutes before eating, as they inhibit the proton pump during its activation by food consumption. Morning dosing before breakfast provides optimal 24-hour acid suppression."),
  q("RPN-CAT","Pharmacology",3,"Amphotericin B therapy requires monitoring for:",["Hepatotoxicity primarily","Nephrotoxicity, hypokalemia, and hypomagnesemia","Cardiotoxicity","Pulmonary fibrosis"],1,"Amphotericin B is highly nephrotoxic and causes electrolyte wasting (hypokalemia, hypomagnesemia). Normal saline prehydration and electrolyte supplementation reduce toxicity. BUN, creatinine, and electrolytes require frequent monitoring."),
  q("REX-PN","Mental Health",3,"A client with anorexia nervosa on a refeeding protocol is at risk for which potentially fatal electrolyte abnormality?",["Hypernatremia","Hypophosphatemia (refeeding syndrome)","Hyperkalemia","Hypercalcemia"],1,"Refeeding syndrome's hallmark is severe hypophosphatemia caused by insulin-driven intracellular phosphorus shift when carbohydrates are reintroduced. This can cause cardiac arrhythmias, respiratory failure, seizures, and death."),
  q("REX-PN","Pediatrics",3,"A child with juvenile idiopathic arthritis has morning stiffness. The nurse teaches:",["Keep the child in bed until stiffness passes","Apply warm packs and encourage gentle morning movement and ROM exercises","Use ice packs on all joints","Give aspirin before waking"],1,"JIA morning stiffness responds well to warmth (warm bath, heating pads) followed by gentle range of motion exercises. Warmth increases blood flow, reduces stiffness, and improves mobility. NSAIDs (not aspirin) are used as prescribed."),
  q("REX-PN","Fundamentals",2,"When documenting in the medical record, the nurse should:",["Use personal abbreviations for efficiency","Document accurately, completely, and in a timely manner using only approved abbreviations","Leave space for future additions","Chart before providing care"],1,"Accurate, complete, timely documentation using only facility-approved abbreviations is essential. The Joint Commission maintains a list of prohibited abbreviations. Never pre-chart, leave blank spaces, or alter existing entries."),
  q("REX-PN","Musculoskeletal",3,"Ankle pump exercises performed by a post-knee replacement client primarily prevent:",["Muscle wasting","Deep vein thrombosis through venous return promotion","Joint stiffness","Pressure ulcers"],1,"Ankle pumps activate the calf muscle pump, promoting venous return and reducing DVT risk. They should be performed frequently (10 repetitions hourly) starting immediately after surgery."),
  q("REX-PN","Renal",2,"An ileal conduit (urostomy) produces urine:",["Only when the client feels the urge to void","Continuously into an external collection appliance","At scheduled intervals","That can be voluntarily controlled"],0,"An ileal conduit diverts urine through a segment of ileum to a stoma on the abdomen. Urine drains continuously and cannot be voluntarily controlled. Proper appliance application and peristomal skin care are essential."),
  q("REX-PN","Maternal/Newborn",2,"A macrosomic newborn (4.5 kg) born to a diabetic mother should be monitored for:",["Hyperglycemia immediately after birth","Hypoglycemia within the first hours of life","Hypernatremia","Polycythemia only"],1,"Infants of diabetic mothers produce excess insulin in response to maternal hyperglycemia. After birth, the glucose supply stops but insulin remains elevated, causing neonatal hypoglycemia. Blood glucose should be checked within 1-2 hours of birth."),
  q("REX-PN","Cardiovascular",3,"A client receiving thrombolytic therapy should NOT undergo which procedure?",["Blood pressure monitoring","Arterial puncture or invasive procedures","Pulse oximetry","Cardiac monitoring"],1,"Thrombolytics increase bleeding risk significantly. Arterial punctures, IM injections, venipunctures, and invasive procedures should be minimized for 24 hours. Pressure dressings should be applied at necessary access sites."),
  q("REX-PN","Respiratory",3,"A client with obstructive sleep apnea is prescribed CPAP. The nurse teaches that CPAP:",["Provides intermittent positive pressure for ventilation","Delivers continuous positive airway pressure to prevent upper airway collapse during sleep","Delivers oxygen under high pressure","Provides nebulized medications during sleep"],1,"CPAP delivers continuous pressurized air through a mask to splint the upper airway open during sleep, preventing the soft tissue collapse that causes obstructive apnea episodes. Regular use improves oxygenation and reduces daytime sleepiness."),
  q("REX-PN","Neurological",2,"For acute migraine treatment, sumatriptan should be taken:",["Daily for prevention","At the onset of migraine symptoms for acute relief","With MAO inhibitors for enhanced effect","Only for tension-type headaches"],1,"Sumatriptan (5-HT receptor agonist) is most effective when taken at migraine onset. It should not be combined with MAOIs or ergotamines due to serotonin syndrome risk. Maximum daily doses must not be exceeded."),
  q("RPN-CAT","Endocrine",3,"Hashimoto thyroiditis progressing to myxedema presents with:",["Warm, moist skin and tachycardia","Cool, dry skin, facial puffiness, periorbital edema, and bradycardia","Weight loss and hyperactivity","Exophthalmos and lid lag"],1,"Myxedema represents severe hypothyroidism with nonpitting edema (mucopolysaccharide deposits), cool dry skin, facial puffiness, bradycardia, hypothermia, and mental sluggishness. Myxedema coma is the life-threatening extreme requiring IV levothyroxine."),
  q("REX-PN","Gastrointestinal",3,"In palliative care for malignant bowel obstruction with intractable vomiting, the nurse should prepare for:",["Aggressive surgical intervention","Placement of a venting gastrostomy tube for symptom-relieving decompression","Large-volume enemas","Stimulant laxatives"],1,"A venting gastrostomy tube provides continuous decompression and comfort for malignant bowel obstruction in palliative settings, avoiding the discomfort of a prolonged nasogastric tube while allowing small oral intake for comfort."),
  q("REX-PN","Pharmacology",2,"Eye drops are properly administered by instilling medication into:",["The center of the cornea directly","The lower conjunctival sac while the client looks upward","The upper eyelid margin","The inner canthus with the eye closed"],1,"Eye drops are placed into the lower conjunctival sac to prevent corneal damage and ensure proper distribution. The client looks up, the nurse gently pulls down the lower lid, and drops are instilled without touching the dropper to the eye."),
  q("REX-PN","Mental Health",2,"Before administering a PRN anxiolytic, the nurse should first:",["Administer immediately upon client request","Assess current anxiety level and try non-pharmacological interventions","Wait until the client asks three times","Check if the client has ever taken the medication"],1,"Non-pharmacological approaches (deep breathing, grounding techniques, progressive muscle relaxation) should be tried before administering PRN anxiolytics. Assessment of current anxiety level helps determine if medication is truly necessary."),
  q("REX-PN","Pediatrics",3,"A child with Kawasaki disease must be monitored for which cardiac complication?",["Mitral valve prolapse","Coronary artery aneurysm development","Ventricular septal defect","Atrial fibrillation"],1,"Kawasaki disease causes vasculitis of medium-sized arteries, particularly coronary arteries. Aneurysms develop in 15-25% of untreated children. IV immunoglobulin plus high-dose aspirin given early significantly reduces this risk."),
  q("RPN-CAT","Pediatrics",2,"Pediatric IV maintenance fluids calculated by Holliday-Segar method for a 10 kg child is:",["500 mL per 24 hours","1000 mL per 24 hours (approximately 40 mL/hour)","1500 mL per 24 hours","2000 mL per 24 hours"],1,"Holliday-Segar: 100 mL/kg/day for the first 10 kg = 1000 mL/day for a 10 kg child, approximately 42 mL/hour. This provides adequate maintenance hydration for the child's metabolic requirements."),
  q("REX-PN","Fundamentals",2,"The nurse documents a client's pain assessment using which validated tool components?",["Only the client's facial expression","PQRST: Provocation, Quality, Region/Radiation, Severity, Timing","Body temperature and blood pressure only","Observer rating scale without client input"],1,"Comprehensive pain assessment uses PQRST (or OLDCARTS): identifying what provokes/palliates pain, quality, region/radiation, severity on a scale, and timing. This combines subjective (client report) and objective (observations) data."),
  q("REX-PN","Fundamentals",2,"When applying elastic compression bandages to a lower extremity, the nurse wraps from:",["Proximal to distal (thigh to ankle)","Distal to proximal (ankle to thigh)","Any direction for convenience","Center outward"],1,"Elastic bandages are applied distal to proximal to promote venous return and prevent blood pooling. Even tension and 50% overlap ensure consistent compression. Assess circulation after application."),
  q("REX-PN","Renal",3,"During hemodialysis, a client develops disequilibrium syndrome. Symptoms include:",["Hypertension and peripheral edema","Headache, nausea, confusion, and possible seizures","Improved energy and clear mentation","Decreased BUN only with no symptoms"],1,"Dialysis disequilibrium results from rapid solute removal creating an osmotic gradient that draws water into brain cells. Symptoms range from headache and nausea to confusion, seizures, and coma. Slowing the dialysis rate may help prevent it."),
  q("REX-PN","Cardiovascular",2,"Women experiencing myocardial infarction most commonly present with:",["Classic crushing substernal chest pain","Atypical symptoms including fatigue, shortness of breath, jaw pain, and nausea","Sudden loss of consciousness","Severe lower extremity pain"],1,"Women often present with atypical MI symptoms: fatigue, dyspnea, jaw/back pain, nausea, and indigestion rather than classic chest pain. This contributes to delayed recognition and treatment of MI in women."),
  q("REX-PN","Respiratory",2,"Chest physiotherapy should be scheduled:",["Immediately after meals","At least 1 hour before or 2 hours after eating","Only at bedtime","When the client reports chest congestion"],1,"CPT should be performed on an empty stomach (1 hour before or 2 hours after meals) to prevent nausea and aspiration. Postural drainage with percussion and vibration mobilizes secretions for expectoration."),
  q("REX-PN","Neurological",3,"ALS (amyotrophic lateral sclerosis) ultimately causes respiratory failure because it affects:",["Sensory neurons and proprioception","Motor neurons controlling skeletal muscles including respiratory muscles","The cerebellum and coordination","Autonomic nervous system function"],1,"ALS is a progressive motor neuron disease causing skeletal muscle wasting. As respiratory muscles weaken, ventilatory support becomes necessary. Cognitive function and sensation remain intact. Death typically results from respiratory failure."),
  q("RPN-CAT","Endocrine",3,"SIADH (syndrome of inappropriate antidiuretic hormone) is managed primarily with:",["Aggressive IV fluid administration","Fluid restriction to allow sodium levels to normalize","High-dose diuretics","Increased dietary sodium alone"],1,"SIADH causes excessive water retention and dilutional hyponatremia. Fluid restriction (500-1000 mL/day) is the primary treatment. Severe cases may require hypertonic saline (3%) and/or demeclocycline or tolvaptan to promote free water excretion."),
  q("REX-PN","Infection Control",3,"Varicella (chickenpox) requires which type of isolation precautions?",["Standard precautions only","Both airborne AND contact precautions","Droplet precautions only","Contact precautions only"],1,"Varicella requires airborne precautions (negative-pressure room, N95 respirator) because the virus is transmitted via small airborne particles, AND contact precautions because vesicle fluid is also infectious on direct contact."),
  q("REX-PN","Hematological",2,"A client with sickle cell disease should be instructed to:",["Limit fluid intake to concentrate the blood","Maintain adequate hydration of 2-3 liters daily to prevent sickling","Exercise vigorously in hot weather","Avoid all physical activity"],1,"Dehydration increases blood viscosity and promotes RBC sickling. Maintaining hydration (2-3 L/day) is essential. Other preventive measures include avoiding extreme temperatures, high altitude, and promptly treating infections."),
  q("RPN-CAT","Hematological",3,"When a severely thrombocytopenic client receives a platelet transfusion, the nurse monitors for:",["Immediate normalization of platelet count","Transfusion reactions, fever, and incremental platelet count increase","No monitoring is required","Hemolytic reaction only"],0,"Platelet transfusions require monitoring for allergic reactions, febrile reactions, and fluid overload. Each unit increases the count by approximately 5,000-10,000/mm3. Post-transfusion platelet count is checked 1 hour and 24 hours after infusion."),
  q("REX-PN","Integumentary",3,"The greatest systemic risk in the first 24-48 hours after major burns is:",["Wound infection","Hypovolemic shock from massive fluid shifts","Renal failure from dehydration alone","Sepsis from wound colonization"],1,"Massive capillary permeability after major burns causes fluid to shift from intravascular to interstitial space, leading to hypovolemic shock. The Parkland formula guides resuscitation: 4 mL x kg body weight x %TBSA burned in the first 24 hours."),
  q("REX-PN","Immunological",2,"Vaccination provides which type of immunity?",["Passive immunity with immediate effect","Active immunity through stimulating the body's own immune response","Passive natural immunity","No significant immune protection"],1,"Vaccines provide active immunity by exposing the immune system to antigens, stimulating antibody production and immunological memory. Protection develops over weeks but is long-lasting. Passive immunity (immune globulin) is immediate but temporary."),
  q("REX-PN","Reproductive",3,"Endometriosis treatment options include:",["Antibiotics for the inflammatory process","Hormonal therapy to suppress ovulation combined with pain management and possible surgery","Increased physical activity during menstruation only","Dietary modifications as sole treatment"],1,"Endometriosis management includes hormonal therapy (OCPs, GnRH agonists, progestins), NSAIDs for pain, and surgical options (laparoscopic excision/ablation or hysterectomy for severe cases). Treatment is individualized based on symptoms and fertility goals."),
  q("REX-PN","Emergency",3,"A client with heat stroke (core temperature 41C, altered mental status) requires:",["Antipyretic medication administration","Immediate aggressive external cooling with ice packs to major vessels","Natural temperature decrease without intervention","Warm IV fluid administration"],1,"Heat stroke is a medical emergency requiring immediate cooling: ice packs to groin, axillae, and neck target large blood vessels. Additional methods include cool mist fans, cool IV fluids, and ice water immersion. Target is temperature < 39C within 30 minutes."),
  q("REX-PN","Oncology",3,"Radiation therapy to the abdomen causing persistent diarrhea should be managed with:",["High-fiber diet to add bulk","Low-residue diet with adequate hydration","Increased dairy product consumption","Large, infrequent meals"],1,"Radiation enteritis management includes low-residue (low-fiber) diet to reduce bowel stimulation, adequate fluid replacement, antidiarrheal medications as prescribed, and avoiding irritating foods including dairy, caffeine, and spicy foods."),
  q("RPN-CAT","Perioperative",2,"A preoperative client who ate breakfast 2 hours before surgery should have this information:",["Documented but surgery proceeds as planned","Reported to the surgeon immediately as NPO requirements are violated","Noted without informing anyone","Treated by administering an antiemetic"],1,"Eating within the NPO time frame violates anesthesia safety requirements, significantly increasing aspiration risk during induction. The surgeon and anesthesiologist must be notified, and the procedure may need to be postponed."),
  q("REX-PN","Safety",2,"When using a mechanical lift for client transfers, the nurse should:",["Operate the lift independently","Ensure proper sling placement with at least two trained staff members present","Have the client hold onto the lift frame","Move the lift as quickly as possible"],1,"Mechanical lifts require proper sling assessment and placement with at least two trained staff for safe operation. The client should not hold onto the frame. Slow, smooth movements maintain safety. Equipment inspection before each use is essential."),
  q("REX-PN","Geriatrics",2,"The Morse Fall Scale is used to assess:",["Pressure injury risk","Fall risk based on multiple clinical factors","Pain severity","Nutritional status"],1,"The Morse Fall Scale evaluates fall risk using six criteria: history of falling, secondary diagnosis, ambulatory aid use, IV/heparin lock, gait impairment, and mental status. Scores guide fall prevention interventions."),
  q("REX-PN","Community Health",2,"When teaching community fire safety, the most important recommendation is:",["Installing and maintaining working smoke detectors on every level","Having fire extinguishers in every room","Using only fireproof building materials","Avoiding candle use entirely"],0,"Working smoke detectors reduce fire death risk by approximately 50%. They should be installed on every level, in every bedroom, and outside sleeping areas. Monthly testing and annual battery replacement are essential maintenance."),
  q("REX-PN","Wound Care",3,"Negative pressure wound therapy (wound VAC) requires:",["Daily dressing changes","An airtight seal around the wound for proper vacuum function","Application of foam directly to exposed blood vessels","Disconnection during all client activities"],1,"NPWT requires an airtight seal for the vacuum to function. The foam is custom-cut to fill the wound, covered with adhesive drape, and connected to controlled suction. Never apply directly to exposed vessels, nerves, or organs."),
  q("RPN-CAT","Geriatrics",3,"In elderly clients, decreased serum albumin levels affect drug therapy because:",["Drug absorption is enhanced","More free (unbound) drug is available in circulation, increasing toxicity risk","Protein-bound drugs are eliminated faster","There is no clinical significance"],1,"Age-related albumin decline reduces protein binding capacity, leaving more unbound drug in circulation. This increases the pharmacological effect and toxicity risk for highly protein-bound medications, potentially necessitating dose adjustments."),
  q("REX-PN","Cardiovascular",3,"A client with left-sided heart failure has bilateral crackles. Elevating the head of bed promotes:",["Better access for physical examination","Decreased pulmonary congestion and reduced work of breathing","Increased cardiac preload","Improved peripheral circulation only"],1,"High Fowler's position (45-90 degrees) uses gravity to redistribute fluid away from the lungs, decreasing pulmonary congestion, reducing preload, and easing breathing effort in left heart failure."),
  q("REX-PN","Respiratory",3,"ABG results of pH 7.32, PaCO2 58, HCO3 32 in a COPD client indicate:",["Uncompensated respiratory acidosis","Partially compensated respiratory acidosis","Fully compensated metabolic alkalosis","Normal values for COPD"],1,"pH is acidotic (7.32), PaCO2 is elevated (causing acidosis), and HCO3 is elevated (renal compensation). Since pH is still abnormal, this is partially compensated respiratory acidosis, typical of chronic COPD with acute exacerbation."),
  q("REX-PN","Endocrine",3,"A diabetic client with peripheral neuropathy should:",["Use heating pads on numb feet for comfort","Test bath water temperature with hands or thermometer before entering","Walk barefoot for foot strengthening","Cut toenails close to the nail bed"],1,"Peripheral neuropathy impairs sensation. Testing water temperature with hands (not feet) prevents burns. Additional precautions: wear shoes always, daily foot inspection, podiatrist nail care, and well-fitting shoes."),
  q("REX-PN","Gastrointestinal",2,"GERD management includes which lifestyle modification?",["Eating large meals before bedtime","Lying flat immediately after eating","Elevating the head of bed 6-8 inches","Increasing coffee and chocolate intake"],2,"HOB elevation uses gravity to prevent gastric acid reflux. Other measures include small meals, avoiding eating 2-3 hours before bed, avoiding triggers (caffeine, chocolate, alcohol, spicy foods), weight loss, and smoking cessation."),
  q("REX-PN","Pharmacology",2,"Penicillin-allergic clients should be assessed for cross-sensitivity to:",["Macrolide antibiotics","Cephalosporins (beta-lactam structure similarity)","Fluoroquinolones","Aminoglycosides"],1,"Penicillin and cephalosporins share a beta-lactam ring structure with 1-10% cross-reactivity. The provider must be informed of penicillin allergy before prescribing any cephalosporin. True anaphylaxis to penicillin warrants cephalosporin avoidance."),
  q("REX-PN","Fundamentals",2,"Preventing skin breakdown from a bedpan requires:",["Leaving the bedpan in place until the client finishes fully","Prompt removal with thorough skin cleansing after use","Using metal bedpans exclusively","Applying powder before placement"],1,"Prolonged bedpan contact causes friction, pressure, and moisture damage. Prompt removal and thorough skin cleansing prevent breakdown. Use fracture pans for clients unable to raise their hips. Apply barrier cream if needed."),
  q("RPN-CAT","Cardiovascular",3,"First-line rate control medications for atrial fibrillation include:",["Amiodarone as initial therapy","Beta-blockers (metoprolol) or calcium channel blockers (diltiazem)","Digoxin as sole first-line agent","Flecainide for rate control"],1,"Beta-blockers and non-dihydropyridine calcium channel blockers are first-line for AF rate control. Target resting heart rate is < 110 bpm for lenient control. Digoxin is second-line or adjunctive, particularly in heart failure."),
  q("REX-PN","Respiratory",2,"An incentive spirometer should be used postoperatively:",["Once daily for a long session","10 slow deep breaths every 1-2 hours while awake","Only when feeling short of breath","By exhaling forcefully into the device"],1,"Incentive spirometry prevents postoperative atelectasis. The client inhales slowly to raise the indicator, holds for 3-5 seconds, then exhales normally. Performing 10 breaths every 1-2 hours while awake is recommended."),
  q("REX-PN","Neurological",3,"A migraine with aura patient should be placed in:",["A brightly lit room","A dark, quiet room with reduced sensory stimulation","A busy common area for distraction","An upright position in bright light"],1,"Migraine with aura causes photophobia and phonophobia. Dark, quiet environments reduce sensory aggravation. Additional interventions include cold compresses, prescribed medications (triptans, NSAIDs), and relaxation techniques."),
  q("REX-PN","Endocrine",2,"Addison disease causes characteristic:",["Pale, dry skin","Hyperpigmentation of skin folds, palmar creases, and gingival margins","Yellow-tinged sclera","Widespread petechiae"],1,"Primary adrenal insufficiency (Addison disease) increases ACTH production, which stimulates melanocytes causing hyperpigmentation. Darkening is prominent in skin folds, creases, scars, and oral mucosa."),
  q("REX-PN","Gastrointestinal",3,"After total gastrectomy, pernicious anemia develops because:",["The stomach produces intrinsic factor essential for vitamin B12 absorption","Vitamin B12 is stored in the stomach wall","Iron absorption occurs only in the stomach","Folate is synthesized by gastric cells"],0,"Gastric parietal cells produce intrinsic factor necessary for B12 absorption in the terminal ileum. Without intrinsic factor after gastrectomy, B12 cannot be absorbed orally and requires lifelong IM injection supplementation."),
  q("RPN-CAT","Mental Health",3,"Clients taking MAOIs should avoid which foods?",["Fresh fruits and most vegetables","Aged cheese, smoked meats, fermented foods, and red wine","Whole grain products","Lean proteins and fish"],1,"MAOIs inhibit tyramine metabolism. Tyramine-rich foods (aged cheese, cured meats, fermented products, red wine, soy sauce) can cause hypertensive crisis with severe headache, nausea, potential stroke, and death."),
  q("REX-PN","Pediatrics",2,"When examining a 2-year-old toddler, the nurse should begin with:",["Invasive assessments (ears, throat) first","Least invasive assessments first (observation, heart, lungs) using play and distraction","The exact same approach used for adults","Only assessments the child cooperates with"],1,"Toddlers are fearful and uncooperative. Starting with least threatening assessments reduces anxiety. Use distraction, allow the child to handle equipment, and involve parents. Save invasive examinations (ears, throat) for last."),
  q("REX-PN","Musculoskeletal",3,"The key difference between osteoarthritis and rheumatoid arthritis is that OA:",["Involves symmetrical joint inflammation","Has morning stiffness lasting less than 30 minutes and lacks systemic inflammation","Causes rheumatoid nodule formation","Is an autoimmune disease"],1,"OA causes localized joint degeneration with brief morning stiffness (< 30 minutes), asymmetric weight-bearing joint involvement, and no systemic inflammation. RA is autoimmune with prolonged stiffness (> 1 hour), symmetrical involvement, and systemic symptoms."),
  q("REX-PN","Renal",2,"The most common cause of catheter-associated UTI is:",["Using a properly sized catheter","Breaking the closed drainage system during specimen collection","Maintaining the bag below bladder level","Performing regular perineal hygiene"],1,"Breaking the closed drainage system (disconnecting tubing, opening the system for specimens) allows bacteria to enter. Use the self-sealing specimen port. Other prevention includes maintaining closed drainage, perineal hygiene, and early catheter removal."),
  q("RPN-CAT","Maternal/Newborn",3,"A firm, midline fundus at or below the umbilicus postpartum indicates:",["Need for fundal massage","Adequate uterine contraction with low hemorrhage risk","Uterine atony requiring intervention","Need for oxytocin augmentation"],0,"A firm, midline fundus demonstrates adequate myometrial contraction minimizing hemorrhage risk. A boggy (soft) or displaced fundus indicates uterine atony, the most common cause of postpartum hemorrhage, requiring fundal massage and possible oxytocin administration."),
  q("REX-PN","Infection Control",3,"The correct sequence for removing PPE upon exiting an isolation room is:",["Mask first, then gown, then gloves","Gloves first, then gown, eye protection, and mask last (removed outside the room)","Any convenient order","Gown first, then mask and gloves together"],1,"PPE removal order minimizes self-contamination: gloves (most contaminated) first, gown, eye protection, then mask/respirator (removed outside the room). Hand hygiene after removing gloves and again after all PPE is removed."),
  q("REX-PN","Hematological",3,"In hemophilia A with hemarthrosis (joint bleeding), the nurse should:",["Apply heat and encourage active ROM exercises","Immobilize the joint, apply ice, and administer factor VIII replacement","Administer aspirin for pain and swelling","Encourage weight-bearing to reduce stiffness"],1,"Hemarthrosis management: immobilize the joint, apply ice (reduces swelling/bleeding), and administer factor VIII. Heat and ROM increase bleeding. Aspirin is contraindicated as it impairs platelet function."),
  q("REX-PN","Integumentary",2,"A flat, non-palpable, discolored skin lesion less than 1 cm in diameter is classified as a:",["Papule","Macule","Vesicle","Nodule"],1,"Macule: flat, non-palpable, < 1 cm with color change (freckle, petechiae). Papule: elevated, < 1 cm. Vesicle: fluid-filled blister, < 1 cm. Nodule: firm, elevated, > 1 cm."),
  q("REX-PN","Immunological",3,"An immunosuppressed transplant client who develops fever of 38.5C requires:",["Acetaminophen and home observation","Immediate blood cultures and provider notification","Routine vital sign monitoring only","Increased oral fluid intake as sole intervention"],1,"Immunosuppressed clients cannot mount normal immune responses. Even low-grade fever may indicate serious infection requiring urgent blood cultures, comprehensive workup, and prompt antimicrobial therapy. Infections can progress rapidly to sepsis in these patients."),
  q("REX-PN","Reproductive",2,"Post-mastectomy, the affected arm should be positioned:",["Below heart level for drainage","Elevated on pillows above heart level to promote lymphatic drainage","In a sling against the body","In a dependent position"],1,"Elevating the affected arm above heart level promotes lymphatic drainage and reduces edema risk. This begins immediately postoperatively. Gradual exercises and lymphedema prevention education are important components of recovery care."),
  q("REX-PN","Emergency",2,"A Glasgow Coma Scale score of 15 indicates:",["Severe brain injury","Moderate brain injury","Mild brain injury","Fully intact neurological function"],3,"GCS maximum score of 15: eye opening spontaneous (4) + verbal orientation intact (5) + motor commands obeyed (6) = 15. This indicates full neurological function. Scores 13-15 = mild, 9-12 = moderate, 3-8 = severe brain injury."),
  q("REX-PN","Cardiovascular",3,"Dual RAAS blockade (ACE inhibitor combined with ARB) increases the risk of:",["Hypoglycemia","Severe hypotension, hyperkalemia, and renal impairment","Tachycardia","Fluid volume overload"],1,"Combining ACEi and ARB blocks the renin-angiotensin system at two points, significantly increasing hypotension, hyperkalemia, and AKI risk without clear mortality benefit. Current guidelines generally advise against this combination."),
  q("REX-PN","Respiratory",3,"A client with a permanent tracheostomy should be taught to:",["Leave the stoma uncovered during showering","Use a stoma cover or shield to prevent water aspiration during bathing","Stop using humidification since natural airway is bypassed","Remove the tracheostomy for swimming"],1,"Tracheostomy clients must protect the stoma from water entry as the bypassed upper airway means water can directly enter the lungs. Stoma covers/shields during bathing are essential. Continued humidification replaces the natural warming and moistening function."),
  q("REX-PN","Neurological",2,"A client with Bell palsy requires which specific eye care?",["No special eye care needed","Right eye protection if the right side is paralyzed, as the eyelid cannot close","Bilateral eye patching at all times","Application of heat to both eyes"],1,"Bell palsy causes unilateral facial paralysis preventing eyelid closure on the affected side, risking corneal drying and damage. Eye protection includes artificial tears during the day, taping the eye or using an eye patch at night, and protective eyewear."),
  q("REX-PN","Endocrine",3,"Pre-operative pheochromocytoma management requires:",["Beta-blocker therapy as the first agent","Alpha-adrenergic blockade first (10-14 days), THEN beta-blockade","Immediate surgery without medication preparation","Calcium channel blocker monotherapy"],1,"Alpha-blockade (phenoxybenzamine) must precede beta-blockade. Starting beta-blockers first without alpha coverage causes unopposed alpha-adrenergic stimulation and dangerous hypertensive crisis. The alpha-blockade also allows intravascular volume expansion."),
  q("REX-PN","Pharmacology",3,"Vancomycin monitoring includes watching for which serious adverse effects besides Red Man Syndrome?",["Hepatotoxicity only","Ototoxicity and nephrotoxicity","Pulmonary fibrosis","Increased platelet production"],1,"Vancomycin is nephrotoxic (monitor trough levels and creatinine) and ototoxic (hearing loss, tinnitus). Risk increases with concurrent aminoglycoside use. Trough goals are 15-20 mcg/mL for serious infections."),
  q("RPN-CAT","Pharmacology",2,"Alendronate (Fosamax) for osteoporosis should be taken:",["At bedtime with a snack","First thing in the morning with a full glass of water, remaining upright for 30-60 minutes","Crushed and mixed with food","With calcium supplements simultaneously"],1,"Bisphosphonates require empty stomach administration with plain water and upright positioning for 30-60 minutes to prevent severe esophageal irritation and ulceration. Do not take with food, other beverages, or medications."),
  q("REX-PN","Mental Health",2,"SSRIs typically reach full therapeutic effect within:",["24-48 hours","2-4 weeks","3-6 months","6-12 months"],1,"SSRIs require 2-4 weeks for neurotransmitter level stabilization and receptor sensitivity changes. Clients should continue medication through this period. Side effects may appear before therapeutic benefits, requiring patient education and encouragement."),
  q("REX-PN","Pediatrics",3,"A 6-month-old with RSV bronchiolitis showing nasal flaring and retractions requires:",["Antibiotic therapy","Supportive care focusing on adequate oxygenation and hydration","Antiviral medication as first-line","Chest physiotherapy"],1,"RSV bronchiolitis is managed supportively: oxygen supplementation if SpO2 < 90%, hydration (IV or NG if unable to feed), nasal suctioning, and respiratory monitoring. Antibiotics are ineffective against viruses. Palivizumab is prophylactic only."),
  q("REX-PN","Fundamentals",2,"A weight gain of 2 kg overnight indicates approximately how much fluid retention?",["500 mL","1,000 mL","2,000 mL","3,000 mL"],2,"One kilogram of weight gain equals approximately 1,000 mL of retained fluid. Therefore 2 kg = 2,000 mL retention. Daily weights are the most accurate method for monitoring fluid balance in edematous conditions."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RPN-B4] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
